use openssl_crypto::context::LibContext;
use openssl_crypto::dsa::{
    sign as dsa_sign_primitive, verify as dsa_verify_primitive, DsaParams, DsaPrivateKey,
    DsaPublicKey,
};
use openssl_crypto::evp::md::{
    digest_one_shot, MdContext, MessageDigest, SHA1, SHA224, SHA256, SHA384, SHA3_224, SHA3_256,
    SHA3_384, SHA3_512, SHA512,
};

use super::OperationMode;
use crate::implementations::algorithm;
use crate::traits::{AlgorithmDescriptor, SignatureContext, SignatureProvider};

// =============================================================================
// NonceType â€” replaces C integer `nonce_type` in PROV_DSA_CTX
// =============================================================================

/// DSA nonce selection strategy.
///
/// Replaces the C `nonce_type` integer field from `PROV_DSA_CTX` (see
/// `providers/implementations/signature/dsa_sig.c`). Rule R5 â€” instead of
/// using `0` (random) and `1` (deterministic) as magic values we expose an
/// exhaustive enum.
///
/// # Variants
///
/// * [`NonceType::Default`] â€” FIPS 186-4 Â§4.5 random-`k` signing. This is
///   the only value currently honoured by the underlying
///   [`openssl_crypto::dsa::sign`] primitive.
/// * [`NonceType::Deterministic`] â€” FIPS 186-5 / RFC 6979 deterministic
///   derivation of `k` from the message and the private key. The Rust
///   crypto layer does not yet implement deterministic-`k`; selecting this
///   variant causes [`DsaSignatureContext::sign_init`] to fail fast with
///   [`ProviderError::AlgorithmUnavailable`] rather than silently producing
///   a random-nonce signature.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum NonceType {
    /// Random-`k` nonce per FIPS 186-4 Â§4.5 (the default).
    Default,
    /// Deterministic-`k` nonce per RFC 6979 (not currently supported).
    Deterministic,
}

impl Default for NonceType {
    fn default() -> Self {
        Self::Default
    }
}

impl NonceType {
    /// Parses a nonce-type selector from the provider-parameter `u64`
    /// encoding used by the `"nonce-type"` OSSL parameter.
    ///
    /// The C source (`dsa_sig.c`) uses `0` for random (the historical
    /// default) and `1` for deterministic / RFC 6979 behaviour. Any other
    /// value is rejected.
    fn from_raw(value: u64) -> Result<Self, CommonError> {
        match value {
            0 => Ok(Self::Default),
            1 => Ok(Self::Deterministic),
            other => Err(CommonError::InvalidArgument(format!(
                "DSA nonce-type parameter {other} is not recognised (expected 0 or 1)"
            ))),
        }
    }

    /// Returns the `u64` encoding consumed by the `"nonce-type"` parameter.
    fn as_raw(self) -> u64 {
        match self {
            Self::Default => 0,
            Self::Deterministic => 1,
        }
    }
}

// =============================================================================
// DsaVariant â€” dispatch identity for the 10 descriptor entries
// =============================================================================

/// Enumerates the 10 DSA signature descriptor variants exported by this
/// provider.
///
/// The composable variant is used by the "EVP high-level / `PKEY_CTX`" style of
/// API where the caller supplies the digest at a later step via
/// [`SignatureContext::digest_sign_init`] (or [`set_ctx_params`](SignatureContext::set_params)).
/// The nine per-hash "sigalg" variants are fixed to a single digest and
/// correspond to the `IMPL_DSA_SIGALG(...)` macro expansions in
/// `dsa_sig.c` lines 1000â€“1068.
///
/// # C mapping
///
/// * [`DsaVariant::Composable`] â†” `ossl_dsa_signature_functions`
/// * [`DsaVariant::Sha1`] â†” `ossl_dsa_sha1_signature_functions`
/// * [`DsaVariant::Sha224`] â†” `ossl_dsa_sha224_signature_functions`
/// * [`DsaVariant::Sha256`] â†” `ossl_dsa_sha256_signature_functions`
/// * [`DsaVariant::Sha384`] â†” `ossl_dsa_sha384_signature_functions`
/// * [`DsaVariant::Sha512`] â†” `ossl_dsa_sha512_signature_functions`
/// * [`DsaVariant::Sha3_224`] â†” `ossl_dsa_sha3_224_signature_functions`
/// * [`DsaVariant::Sha3_256`] â†” `ossl_dsa_sha3_256_signature_functions`
/// * [`DsaVariant::Sha3_384`] â†” `ossl_dsa_sha3_384_signature_functions`
/// * [`DsaVariant::Sha3_512`] â†” `ossl_dsa_sha3_512_signature_functions`
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum DsaVariant {
    /// Generic composable DSA â€” the digest is configured by the caller.
    Composable,
    /// Fixed sigalg bound to SHA-1.
    Sha1,
    /// Fixed sigalg bound to SHA-224.
    Sha224,
    /// Fixed sigalg bound to SHA-256.
    Sha256,
    /// Fixed sigalg bound to SHA-384.
    Sha384,
    /// Fixed sigalg bound to SHA-512.
    Sha512,
    /// Fixed sigalg bound to SHA3-224.
    Sha3_224,
    /// Fixed sigalg bound to SHA3-256.
    Sha3_256,
    /// Fixed sigalg bound to SHA3-384.
    Sha3_384,
    /// Fixed sigalg bound to SHA3-512.
    Sha3_512,
}

impl DsaVariant {
    /// Returns the canonical algorithm name (exported to the provider
    /// registry and matched by `EVP_SIGNATURE_fetch`).
    #[must_use]
    pub fn name(self) -> &'static str {
        match self {
            Self::Composable => "DSA",
            Self::Sha1 => "DSA-SHA1",
            Self::Sha224 => "DSA-SHA224",
            Self::Sha256 => "DSA-SHA256",
            Self::Sha384 => "DSA-SHA384",
            Self::Sha512 => "DSA-SHA512",
            Self::Sha3_224 => "DSA-SHA3-224",
            Self::Sha3_256 => "DSA-SHA3-256",
            Self::Sha3_384 => "DSA-SHA3-384",
            Self::Sha3_512 => "DSA-SHA3-512",
        }
    }

    /// Returns `true` if this is a fixed-digest "sigalg" variant (not the
    /// composable `"DSA"` entry).
    #[must_use]
    pub fn is_sigalg(self) -> bool {
        !matches!(self, Self::Composable)
    }

    /// Returns the fixed digest name for sigalg variants, or `None` for
    /// [`Self::Composable`] which has no intrinsic digest.
    #[must_use]
    pub fn fixed_digest(self) -> Option<&'static str> {
        match self {
            Self::Composable => None,
            Self::Sha1 => Some(SHA1),
            Self::Sha224 => Some(SHA224),
            Self::Sha256 => Some(SHA256),
            Self::Sha384 => Some(SHA384),
            Self::Sha512 => Some(SHA512),
            Self::Sha3_224 => Some(SHA3_224),
            Self::Sha3_256 => Some(SHA3_256),
            Self::Sha3_384 => Some(SHA3_384),
            Self::Sha3_512 => Some(SHA3_512),
        }
    }
}

// =============================================================================
// DsaSignatureContext â€” PROV_DSA_CTX translation
// =============================================================================

/// Per-operation DSA signature context.
///
/// Rust translation of the C `PROV_DSA_CTX` structure defined in
/// `providers/implementations/signature/dsa_sig.c` lines 72â€“120. Each
/// `DsaSignatureContext` tracks the state of exactly one
/// sign-or-verify operation over its lifetime; callers allocate a fresh
/// context per request and discard it afterwards.
///
/// # Field mapping from `PROV_DSA_CTX`
///
/// | C field                      | Rust field                | Notes                                                         |
/// |------------------------------|---------------------------|---------------------------------------------------------------|
/// | `libctx`                     | `lib_ctx`                 | `Arc<LibContext>` shared with the provider                    |
/// | `propq`                      | `propq`                   | `Option<String>` â€” `None` if no property query configured     |
/// | `dsa` / `dsa_up_ref`         | `private_key`, `public_key` | Separated by operation; held in `Arc` for cheap `duplicate()` |
/// | `operation`                  | `operation`               | `Option<OperationMode>` â€” `None` until `*_init` runs (Rule R5) |
/// | `flag_sigalg`                | `variant`                 | Encoded in the variant enum itself                            |
/// | `flag_allow_md`              | `allow_md_change`         | Disabled on sigalg variants after `digest_*_init`             |
/// | `flag_allow_update/final/oneshot` | `allow_*` booleans   | Lifecycle state machine for digest-sign/verify streaming      |
/// | `md` / `mdname` / `mdnid`    | `md`, `md_name`           | Fetched `MessageDigest` + canonical name                      |
/// | `mdctx`                      | `md_ctx`                  | `MdContext` for streaming operations                          |
/// | `nonce_type`                 | `nonce_type`              | [`NonceType`] enum                                            |
/// | `aid` / `aid_buf` / `aid_len`| `aid_cache`               | Cached DER `AlgorithmIdentifier` bytes                        |
/// | `sig` / `siglen`             | `cached_signature`        | Pre-computed signature bytes for `VERIFY_MESSAGE` mode        |
/// | `sig_alg_buf` / `sig_alg_len`| â€” (handled by `aid_cache`)| Merged into the AID cache                                     |
///
/// # Memory hygiene
///
/// The context implements [`Zeroize`], [`Drop`], and [`ZeroizeOnDrop`] so that
/// the cached private-key reference and the `cached_signature` buffer are
/// scrubbed deterministically when the context is freed. This mirrors the
/// explicit `OPENSSL_clear_free` / `DSA_free` sequence at the end of
/// `dsa_freectx` (`dsa_sig.c` lines 221â€“247).
pub struct DsaSignatureContext {
    /// Shared library context â€” typically the default created in
    /// `OSSL_LIB_CTX_new()`.
    lib_ctx: Arc<LibContext>,
    /// Optional provider-property query string (mirrors `propq` in C).
    propq: Option<String>,
    /// Variant tag controlling digest flexibility (composable vs sigalg).
    variant: DsaVariant,
    /// Private DSA key bound during [`SignatureContext::sign_init`] (or
    /// [`digest_sign_init`](SignatureContext::digest_sign_init)). Shared
    /// ownership allows [`DsaSignatureContext::duplicate`] to clone the
    /// context without deep-copying the key material.
    private_key: Option<Arc<DsaPrivateKey>>,
    /// Public DSA key bound during [`SignatureContext::verify_init`] (or
    /// [`digest_verify_init`](SignatureContext::digest_verify_init)).
    public_key: Option<Arc<DsaPublicKey>>,
    /// Current operation mode, `None` before `*_init`.
    operation: Option<OperationMode>,
    /// `true` if the caller may change the digest via a `"digest"`
    /// parameter; forced to `false` on sigalg variants after
    /// `digest_*_init`.
    allow_md_change: bool,
    /// Digest-sign/verify streaming lifecycle flags â€” mirror the
    /// `flag_allow_update`/`flag_allow_final` pair in the C source.
    allow_update: bool,
    allow_final: bool,
    /// Fetched digest algorithm. Kept in sync with [`Self::md_name`].
    md: Option<MessageDigest>,
    /// Canonical digest name string (case-normalised, never empty).
    md_name: Option<String>,
    /// Streaming digest context, created lazily in `digest_*_init`.
    md_ctx: Option<MdContext>,
    /// Nonce selection strategy.
    nonce_type: NonceType,
    /// Cached DER-encoded `AlgorithmIdentifier` bytes for the currently
    /// configured `variant` + `md_name` combination. Populated lazily on
    /// the first `"algorithm-id"` parameter query.
    aid_cache: Option<Vec<u8>>,
    /// Cached signature bytes for `VERIFYMSG`-style operations, where the
    /// verifier is given the signature upfront and then streams the
    /// message in via `digest_verify_update`. Zeroised on context drop.
    cached_signature: Option<Vec<u8>>,
    /// Buffer accumulating data chunks fed via `digest_sign_update` /
    /// `digest_verify_update`. Consumed in `digest_sign_final` /
    /// `digest_verify_final` and securely scrubbed afterwards. Mirrors
    /// the C `pdsactx->mdctx` update-then-finalize pattern but using a
    /// pure-Rust buffer because the streaming digest handling lives one
    /// layer down in the crypto crate.
    streaming_buffer: Vec<u8>,
}

impl fmt::Debug for DsaSignatureContext {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        // Redact cryptographic material. Arc<DsaPrivateKey> is explicitly
        // marked `ZeroizeOnDrop` so we never log its contents.
        f.debug_struct("DsaSignatureContext")
            .field("variant", &self.variant)
            .field("operation", &self.operation)
            .field("has_private_key", &self.private_key.is_some())
            .field("has_public_key", &self.public_key.is_some())
            .field("md_name", &self.md_name)
            .field("nonce_type", &self.nonce_type)
            .field("allow_md_change", &self.allow_md_change)
            .field("allow_update", &self.allow_update)
            .field("allow_final", &self.allow_final)
            .field(
                "cached_signature_len",
                &self.cached_signature.as_ref().map(Vec::len),
            )
            .field("aid_cache_len", &self.aid_cache.as_ref().map(Vec::len))
            .field("propq", &self.propq)
            .finish_non_exhaustive()
    }
}

impl Zeroize for DsaSignatureContext {
    fn zeroize(&mut self) {
        // `private_key` and `public_key` are dropped â€” `DsaPrivateKey`
        // implements `ZeroizeOnDrop`; the public key has no sensitive
        // material to clear.
        self.private_key = None;
        self.public_key = None;
        if let Some(aid) = self.aid_cache.as_mut() {
            aid.zeroize();
        }
        self.aid_cache = None;
        if let Some(sig) = self.cached_signature.as_mut() {
            sig.zeroize();
        }
        self.cached_signature = None;
        // Scrub the streaming update buffer in case it still holds
        // plaintext (the caller might not have issued the matching
        // `_final` before dropping the context).
        self.streaming_buffer.zeroize();
        self.md_ctx = None;
        self.md = None;
        self.md_name = None;
        self.operation = None;
    }
}

impl Drop for DsaSignatureContext {
    fn drop(&mut self) {
        self.zeroize();
    }
}

impl ZeroizeOnDrop for DsaSignatureContext {}

impl DsaSignatureContext {
    /// Creates a fresh context bound to the given variant, library context,
    /// and optional property query. Called exclusively from
    /// [`DsaSignatureProvider::new_ctx`]; not public API.
    pub(crate) fn new(
        variant: DsaVariant,
        lib_ctx: Arc<LibContext>,
        propq: Option<String>,
    ) -> Self {
        let allow_md_change = !variant.is_sigalg();
        Self {
            lib_ctx,
            propq,
            variant,
            private_key: None,
            public_key: None,
            operation: None,
            allow_md_change,
            allow_update: false,
            allow_final: false,
            md: None,
            md_name: None,
            md_ctx: None,
            nonce_type: NonceType::Default,
            aid_cache: None,
            cached_signature: None,
            streaming_buffer: Vec::new(),
        }
    }

    /// Returns a deep-enough clone of this context suitable for the provider
    /// `dupctx` dispatch entry.
    ///
    /// The key references are shared via `Arc::clone`; everything else is
    /// cloned by value. The fetched digest, if any, is re-usable across
    /// both copies because `MessageDigest` is a value type. The streaming
    /// `MdContext` is re-created lazily so that independent streams do not
    /// interfere with one another.
    #[must_use]
    pub fn duplicate(&self) -> Self {
        Self {
            lib_ctx: Arc::clone(&self.lib_ctx),
            propq: self.propq.clone(),
            variant: self.variant,
            private_key: self.private_key.as_ref().map(Arc::clone),
            public_key: self.public_key.as_ref().map(Arc::clone),
            operation: self.operation,
            allow_md_change: self.allow_md_change,
            allow_update: self.allow_update,
            allow_final: self.allow_final,
            md: self.md.clone(),
            md_name: self.md_name.clone(),
            // Streaming digest state is not meaningfully shareable;
            // deliberately drop it so that the clone starts fresh.
            md_ctx: None,
            nonce_type: self.nonce_type,
            aid_cache: self.aid_cache.clone(),
            cached_signature: self.cached_signature.clone(),
            // Fresh streaming buffer â€” mirrors `md_ctx: None` above.
            // Independent streams must not collide and any partial
            // message accumulated so far belongs only to the original
            // context.
            streaming_buffer: Vec::new(),
        }
    }
}

// =============================================================================
// TLV key-parsing helpers
// =============================================================================

/// TLV version byte currently understood by [`parse_dsa_key`].
const DSA_KEY_TLV_VERSION: u8 = 0x01;

/// Bit mask for the `has_params` flag.
const FLAG_HAS_PARAMS: u8 = 0x01;
/// Bit mask for the `has_public` flag.
const FLAG_HAS_PUBLIC: u8 = 0x02;
/// Bit mask for the `has_private` flag.
const FLAG_HAS_PRIVATE: u8 = 0x04;

/// Output of [`parse_dsa_key`] â€” a decoded key blob.
struct DecodedDsaKey {
    /// Domain parameters (always present in a well-formed blob).
    params: DsaParams,
    /// Public key `y`, if encoded.
    public_y: Option<BigNum>,
    /// Private scalar `x`, if encoded.
    private_x: Option<BigNum>,
}

/// Parses a DSA key blob encoded with the TLV scheme documented at the top
/// of this module.
///
/// This is a strict parser: every length field must be satisfied in full;
/// no trailing bytes are tolerated; an unknown version byte or an
/// unrecognised flags byte causes immediate rejection.
fn parse_dsa_key(bytes: &[u8]) -> Result<DecodedDsaKey, ProviderError> {
    // At minimum: version + flags.
    if bytes.len() < 2 {
        return Err(ProviderError::Init(format!(
            "DSA key blob is too short: received {} bytes, need at least 2",
            bytes.len()
        )));
    }

    let version = bytes[0];
    if version != DSA_KEY_TLV_VERSION {
        return Err(ProviderError::Init(format!(
            "DSA key blob version {version:#04x} not supported (expected {DSA_KEY_TLV_VERSION:#04x})"
        )));
    }

    let flags = bytes[1];
    let recognised_mask = FLAG_HAS_PARAMS | FLAG_HAS_PUBLIC | FLAG_HAS_PRIVATE;
    if flags & !recognised_mask != 0 {
        return Err(ProviderError::Init(format!(
            "DSA key blob flags byte {flags:#04x} contains unrecognised bits \
             (allowed mask {recognised_mask:#04x})"
        )));
    }
    if flags & FLAG_HAS_PARAMS == 0 {
        return Err(ProviderError::Init(
            "DSA key blob is missing the domain-parameter section (has_params bit must be set)"
                .to_string(),
        ));
    }

    let mut cursor = Cursor::new(&bytes[2..]);

    let p = cursor.take_bignum("p")?;
    let q = cursor.take_bignum("q")?;
    let g = cursor.take_bignum("g")?;

    let params = DsaParams::new(p, q, g)
        .map_err(|e| ProviderError::Init(format!("DSA domain parameters rejected: {e}")))?;

    let public_y = if flags & FLAG_HAS_PUBLIC != 0 {
        Some(cursor.take_bignum("y")?)
    } else {
        None
    };

    let private_x = if flags & FLAG_HAS_PRIVATE != 0 {
        Some(cursor.take_bignum("x")?)
    } else {
        None
    };

    if !cursor.is_empty() {
        return Err(ProviderError::Init(format!(
            "DSA key blob has {} trailing bytes after decode",
            cursor.remaining()
        )));
    }

    Ok(DecodedDsaKey {
        params,
        public_y,
        private_x,
    })
}

/// Tiny read-cursor used by [`parse_dsa_key`] â€” avoids pulling in another
/// crate for a handful of length-prefix reads.
struct Cursor<'a> {
    buf: &'a [u8],
    pos: usize,
}

impl<'a> Cursor<'a> {
    fn new(buf: &'a [u8]) -> Self {
        Self { buf, pos: 0 }
    }

    fn remaining(&self) -> usize {
        self.buf.len().saturating_sub(self.pos)
    }

    fn is_empty(&self) -> bool {
        self.remaining() == 0
    }

    fn take(&mut self, n: usize, field: &str) -> Result<&'a [u8], ProviderError> {
        if self.remaining() < n {
            return Err(ProviderError::Init(format!(
                "DSA key blob truncated while reading field '{field}': \
                 have {} bytes, need {n}",
                self.remaining()
            )));
        }
        let slice = &self.buf[self.pos..self.pos + n];
        self.pos += n;
        Ok(slice)
    }

    fn take_u32_be(&mut self, field: &str) -> Result<u32, ProviderError> {
        let bytes = self.take(4, field)?;
        // `try_into` is infallible here because we just asked for 4 bytes.
        let arr: [u8; 4] = bytes
            .try_into()
            .map_err(|_| ProviderError::Init(format!("u32 read failed for '{field}'")))?;
        Ok(u32::from_be_bytes(arr))
    }

    fn take_bignum(&mut self, field: &str) -> Result<BigNum, ProviderError> {
        let len_u32 = self.take_u32_be(&format!("{field}_len"))?;
        if len_u32 == 0 {
            return Err(ProviderError::Init(format!(
                "DSA key blob field '{field}' has zero length"
            )));
        }
        // Rule R6: use `usize::try_from` instead of `as`.
        let len = usize::try_from(len_u32).map_err(|e| {
            ProviderError::Init(format!(
                "DSA key blob field '{field}' length {len_u32} is unrepresentable on this \
                 platform (usize conversion failed: {e})"
            ))
        })?;
        let slice = self.take(len, field)?;
        // `BigNum::from_bytes_be` is infallible (see `crates/openssl-crypto/src/bn/mod.rs`
        // line 459). It accepts any length up to the build-time ceiling.
        Ok(BigNum::from_bytes_be(slice))
    }
}

// =============================================================================
// AlgorithmIdentifier DER construction
// =============================================================================

/// Returns the DER-encoded `AlgorithmIdentifier` bytes for the given
/// variant.
///
/// The encoding is a bare `SEQUENCE { OID }` â€” the `parameters` field is
/// omitted per RFC 3279 Â§2.2.2 for DSA signatures. These are the same
/// byte sequences that `ossl_DER_w_algorithmIdentifier_DSA_with_MD`
/// emits in the C source for each of the nine fixed-digest variants.
///
/// For the composable [`DsaVariant::Composable`], the AID used is the
/// bare `id-dsa` OID (`1.2.840.10040.4.1`). Higher-layer serialisers
/// normally splice the digest-specific OID in after selecting the
/// digest, but for the parameter-query path this is the value that
/// matches the key's own algorithm identifier.
fn algorithm_identifier_der(variant: DsaVariant) -> Vec<u8> {
    match variant {
        // id-dsa = 1.2.840.10040.4.1
        // DER: 30 09 06 07 2A 86 48 CE 38 04 01
        DsaVariant::Composable => vec![
            0x30, 0x09, 0x06, 0x07, 0x2A, 0x86, 0x48, 0xCE, 0x38, 0x04, 0x01,
        ],
        // id-dsa-with-sha1 = 1.2.840.10040.4.3
        DsaVariant::Sha1 => vec![
            0x30, 0x09, 0x06, 0x07, 0x2A, 0x86, 0x48, 0xCE, 0x38, 0x04, 0x03,
        ],
        // id-dsa-with-sha224 = 2.16.840.1.101.3.4.3.1
        DsaVariant::Sha224 => vec![
            0x30, 0x0B, 0x06, 0x09, 0x60, 0x86, 0x48, 0x01, 0x65, 0x03, 0x04, 0x03, 0x01,
        ],
        // id-dsa-with-sha256 = 2.16.840.1.101.3.4.3.2
        DsaVariant::Sha256 => vec![
            0x30, 0x0B, 0x06, 0x09, 0x60, 0x86, 0x48, 0x01, 0x65, 0x03, 0x04, 0x03, 0x02,
        ],
        // id-dsa-with-sha384 = 2.16.840.1.101.3.4.3.3
        DsaVariant::Sha384 => vec![
            0x30, 0x0B, 0x06, 0x09, 0x60, 0x86, 0x48, 0x01, 0x65, 0x03, 0x04, 0x03, 0x03,
        ],
        // id-dsa-with-sha512 = 2.16.840.1.101.3.4.3.4
        DsaVariant::Sha512 => vec![
            0x30, 0x0B, 0x06, 0x09, 0x60, 0x86, 0x48, 0x01, 0x65, 0x03, 0x04, 0x03, 0x04,
        ],
        // id-dsa-with-sha3-224 = 2.16.840.1.101.3.4.3.5
        DsaVariant::Sha3_224 => vec![
            0x30, 0x0B, 0x06, 0x09, 0x60, 0x86, 0x48, 0x01, 0x65, 0x03, 0x04, 0x03, 0x05,
        ],
        // id-dsa-with-sha3-256 = 2.16.840.1.101.3.4.3.6
        DsaVariant::Sha3_256 => vec![
            0x30, 0x0B, 0x06, 0x09, 0x60, 0x86, 0x48, 0x01, 0x65, 0x03, 0x04, 0x03, 0x06,
        ],
        // id-dsa-with-sha3-384 = 2.16.840.1.101.3.4.3.7
        DsaVariant::Sha3_384 => vec![
            0x30, 0x0B, 0x06, 0x09, 0x60, 0x86, 0x48, 0x01, 0x65, 0x03, 0x04, 0x03, 0x07,
        ],
        // id-dsa-with-sha3-512 = 2.16.840.1.101.3.4.3.8
        DsaVariant::Sha3_512 => vec![
            0x30, 0x0B, 0x06, 0x09, 0x60, 0x86, 0x48, 0x01, 0x65, 0x03, 0x04, 0x03, 0x08,
        ],
    }
}

/// Maps a digest name to the corresponding fixed-digest variant (if any).
///
/// Used during `digest_sign_init`/`digest_verify_init` on the composable
/// provider to compute the AID cache for the chosen digest. Returns `None`
/// for XOF or unsupported digests; the caller then leaves the cache unset.
fn variant_for_digest(digest_name: &str) -> Option<DsaVariant> {
    // Digest names arrive in the form emitted by `MessageDigest::name()`
    // which follows the provider's canonical naming (see `evp::md`).
    let normalised = digest_name.to_ascii_uppercase();
    match normalised.as_str() {
        "SHA1" | "SHA-1" => Some(DsaVariant::Sha1),
        "SHA2-224" | "SHA-224" | "SHA224" => Some(DsaVariant::Sha224),
        "SHA2-256" | "SHA-256" | "SHA256" => Some(DsaVariant::Sha256),
        "SHA2-384" | "SHA-384" | "SHA384" => Some(DsaVariant::Sha384),
        "SHA2-512" | "SHA-512" | "SHA512" => Some(DsaVariant::Sha512),
        "SHA3-224" => Some(DsaVariant::Sha3_224),
        "SHA3-256" => Some(DsaVariant::Sha3_256),
        "SHA3-384" => Some(DsaVariant::Sha3_384),
        "SHA3-512" => Some(DsaVariant::Sha3_512),
        _ => None,
    }
}

/// Normalises the digest name a caller provides (e.g. `"sha256"`) to the
/// canonical provider-level form (`"SHA2-256"`) so that both sigalg
/// matching and message-digest fetching are stable under case or alias
/// variation.
fn canonicalise_digest_name(name: &str) -> String {
    let upper = name.to_ascii_uppercase();
    match upper.as_str() {
        "SHA1" | "SHA-1" => SHA1.to_string(),
        "SHA2-224" | "SHA-224" | "SHA224" => SHA224.to_string(),
        "SHA2-256" | "SHA-256" | "SHA256" => SHA256.to_string(),
        "SHA2-384" | "SHA-384" | "SHA384" => SHA384.to_string(),
        "SHA2-512" | "SHA-512" | "SHA512" => SHA512.to_string(),
        "SHA3-224" => SHA3_224.to_string(),
        "SHA3-256" => SHA3_256.to_string(),
        "SHA3-384" => SHA3_384.to_string(),
        "SHA3-512" => SHA3_512.to_string(),
        _ => upper,
    }
}

// =============================================================================
// DsaSignatureContext â€” private helpers shared by trait impls
// =============================================================================

impl DsaSignatureContext {
    /// Binds the parsed key components to the context for a *sign* operation.
    fn install_private_key(&mut self, decoded: DecodedDsaKey) -> ProviderResult<()> {
        let DecodedDsaKey {
            params,
            public_y: _public_y,
            private_x,
        } = decoded;

        let x = private_x.ok_or_else(|| {
            ProviderError::Init(
                "DSA sign_init: the supplied key blob does not carry a private scalar (x)"
                    .to_string(),
            )
        })?;

        let key =
            DsaPrivateKey::from_components(x, params).map_err(|e| map_crypto_key_error(&e))?;
        self.private_key = Some(Arc::new(key));
        Ok(())
    }

    /// Binds the parsed key components to the context for a *verify* operation.
    fn install_public_key(&mut self, decoded: DecodedDsaKey) -> ProviderResult<()> {
        let DecodedDsaKey {
            params,
            public_y,
            private_x: _private_x,
        } = decoded;

        let y = public_y.ok_or_else(|| {
            ProviderError::Init(
                "DSA verify_init: the supplied key blob does not carry a public value (y)"
                    .to_string(),
            )
        })?;

        let key = DsaPublicKey::from_components(y, params).map_err(|e| map_crypto_key_error(&e))?;
        self.public_key = Some(Arc::new(key));
        Ok(())
    }

    /// Fetches the digest algorithm, storing the result in `self.md` and
    /// `self.md_name`. Idempotent when re-invoked with the same name.
    fn setup_digest(&mut self, requested_name: &str) -> ProviderResult<()> {
        if requested_name.is_empty() {
            return Err(ProviderError::Init(
                "DSA setup_digest: digest name must not be empty".to_string(),
            ));
        }

        let canonical = canonicalise_digest_name(requested_name);

        // Fast path: already configured with this digest.
        if self.md_name.as_deref() == Some(canonical.as_str()) && self.md.is_some() {
            trace!(
                digest = %canonical,
                "dsa: setup_digest â€” digest already configured, nothing to do"
            );
            return Ok(());
        }

        let md = MessageDigest::fetch(&self.lib_ctx, &canonical, self.propq.as_deref())
            .map_err(map_crypto_digest_error)?;
        if md.is_xof() {
            return Err(ProviderError::AlgorithmUnavailable(format!(
                "digest '{canonical}' is an XOF and is not suitable for DSA signatures"
            )));
        }

        trace!(
            digest = %canonical,
            digest_size = md.digest_size(),
            "dsa: setup_digest â€” digest fetched and bound to context"
        );

        self.md_name = Some(canonical);
        self.md = Some(md);

        // Invalidate the AID cache â€” the digest just changed.
        if let Some(aid) = self.aid_cache.as_mut() {
            aid.zeroize();
        }
        self.aid_cache = None;

        Ok(())
    }

    /// Validates that the caller-requested digest matches a fixed-sigalg
    /// variant's intrinsic digest. This is a no-op on the composable
    /// variant, where any registered digest is acceptable.
    fn enforce_fixed_digest(&self, requested: &str) -> ProviderResult<()> {
        let Some(fixed) = self.variant.fixed_digest() else {
            return Ok(());
        };
        let canonical = canonicalise_digest_name(requested);
        if canonical != fixed {
            return Err(ProviderError::Common(CommonError::InvalidArgument(
                format!(
                    "{} cannot be used with digest '{requested}' â€” the sigalg is locked to '{fixed}'",
                    self.variant.name()
                ),
            )));
        }
        Ok(())
    }

    /// Computes the AID bytes associated with the current context state.
    ///
    /// For sigalg variants this is a fixed constant; for the composable
    /// variant we attempt to derive an AID from the configured digest
    /// (if any).
    fn compute_aid(&self) -> Vec<u8> {
        match self.variant {
            DsaVariant::Composable => {
                if let Some(digest) = self.md_name.as_deref() {
                    if let Some(v) = variant_for_digest(digest) {
                        return algorithm_identifier_der(v);
                    }
                }
                algorithm_identifier_der(DsaVariant::Composable)
            }
            fixed => algorithm_identifier_der(fixed),
        }
    }

    /// Ensures that `sign_init` / `verify_init` was called before the
    /// caller reaches a `sign`/`verify` (or equivalent) entry point.
    fn require_operation(&self, expected: OperationMode, call: &'static str) -> ProviderResult<()> {
        match self.operation {
            Some(actual) if actual == expected => Ok(()),
            Some(actual) => Err(ProviderError::Common(CommonError::InvalidArgument(
                format!("DSA context is in {actual:?} mode but {call} expects {expected:?}"),
            ))),
            None => Err(ProviderError::Init(format!(
                "DSA {call}: context was not initialised â€” call *_init first"
            ))),
        }
    }

    /// Ensures a key of the correct flavour is bound to the context.
    fn require_private_key(&self, call: &'static str) -> ProviderResult<&Arc<DsaPrivateKey>> {
        self.private_key.as_ref().ok_or_else(|| {
            ProviderError::Init(format!(
                "DSA {call}: no private key bound to context (call sign_init first)"
            ))
        })
    }

    fn require_public_key(&self, call: &'static str) -> ProviderResult<&Arc<DsaPublicKey>> {
        self.public_key.as_ref().ok_or_else(|| {
            ProviderError::Init(format!(
                "DSA {call}: no public key bound to context (call verify_init first)"
            ))
        })
    }

    /// Ensures the selected nonce strategy is supported by the Rust crypto
    /// layer. Deterministic signing has not yet been ported â€” raise an
    /// `AlgorithmUnavailable` error rather than silently falling back.
    fn require_supported_nonce(&self, call: &'static str) -> ProviderResult<()> {
        match self.nonce_type {
            NonceType::Default => Ok(()),
            NonceType::Deterministic => {
                warn!(
                    call = call,
                    "dsa: deterministic nonce (RFC 6979) requested but not supported by the Rust crypto layer"
                );
                Err(ProviderError::AlgorithmUnavailable(format!(
                    "DSA {call}: deterministic-nonce (RFC 6979) signing is not supported by the Rust crypto backend"
                )))
            }
        }
    }
}

// =============================================================================
// Error-mapping helpers
// =============================================================================

/// Converts a [`CryptoError`] returned by the DSA primitive during key
/// construction into a provider-layer `Init` error.
fn map_crypto_key_error(err: &CryptoError) -> ProviderError {
    ProviderError::Init(format!("DSA key rejected by crypto layer: {err}"))
}

/// Converts a digest-fetch failure into a structured provider error.
fn map_crypto_digest_error(err: CryptoError) -> ProviderError {
    match err {
        CryptoError::AlgorithmNotFound(name) => {
            ProviderError::AlgorithmUnavailable(format!("digest '{name}' is not available"))
        }
        other => ProviderError::Dispatch(format!("DSA digest fetch failed: {other}")),
    }
}

/// Converts a [`CryptoError`] returned by the DSA sign primitive into a
/// provider-layer `Dispatch` error. Verification errors are not routed
/// through here â€” the DSA verify primitive distinguishes between
/// "forgery detected" (`Ok(false)`) and "malformed input" (`Err`).
fn map_crypto_sign_error(err: &CryptoError) -> ProviderError {
    ProviderError::Dispatch(format!("DSA sign primitive failed: {err}"))
}

/// Converts a [`CryptoError`] returned by the DSA verify primitive into a
/// provider-layer error. Malformed signatures surface as `Dispatch`
/// errors; the caller still sees a bool for well-formed-but-invalid
/// signatures.
fn map_crypto_verify_error(err: &CryptoError) -> ProviderError {
    ProviderError::Dispatch(format!("DSA verify primitive failed: {err}"))
}

// =============================================================================
// DsaSignatureProvider â€” factory for DSA SignatureContext instances
//
// Replaces the per-variant dispatch table constructors from `dsa_sig.c`:
//   * `ossl_dsa_signature_functions` (composable DSA)
//   * `ossl_dsa_sha1_signature_functions` ... `ossl_dsa_sha3_512_signature_functions`
// Each of these C tables becomes a distinct `DsaSignatureProvider` instance
// parameterised by [`DsaVariant`].  The provider is cheap to clone and is
// expected to outlive the individual signature contexts it spawns.
// =============================================================================

/// Factory type that constructs [`DsaSignatureContext`] instances bound to a
/// particular [`DsaVariant`].
///
/// A provider owns only the *configuration* required to seed a new signing
/// or verifying context â€” the library context handle, the provider property
/// query string and the DSA variant selector.  It contains no per-operation
/// state; all mutable state lives on the spawned [`DsaSignatureContext`].
///
/// # C Mapping
///
/// Replaces the per-algorithm static dispatch tables emitted by the
/// `IMPL_DSA_SIGALG` macro in `providers/implementations/signature/dsa_sig.c`
/// (lines ~985â€“1069).  The macro-generated structures are replaced by a
/// single Rust type whose behaviour is specialised through [`DsaVariant`].
///
/// # Examples
///
/// ```rust,ignore
/// use openssl_provider::implementations::signatures::dsa::{
///     DsaSignatureProvider, DsaVariant,
/// };
/// use openssl_provider::traits::SignatureProvider;
///
/// let provider = DsaSignatureProvider::new(DsaVariant::Sha256);
/// assert_eq!(provider.name(), "DSA-SHA256");
/// let ctx = provider.new_ctx().expect("ctx");
/// ```
#[derive(Debug, Clone)]
pub struct DsaSignatureProvider {
    /// Algorithm variant (composable DSA or one of nine fixed digest sigalgs).
    variant: DsaVariant,

    /// Shared library context used for digest fetching and provider-level
    /// configuration.  Cloned into each new context so spawned contexts
    /// outlive the provider without borrowing from it.
    lib_ctx: Arc<LibContext>,

    /// Optional provider property query string forwarded to every spawned
    /// context.  Typically supplied by the caller during provider
    /// initialisation (`OSSL_PROVIDER_set_default_search_path` equivalent).
    propq: Option<String>,
}

impl DsaSignatureProvider {
    /// Creates a new provider bound to the given [`DsaVariant`] using the
    /// process-wide default library context and no explicit property query.
    ///
    /// This is the entry point used by the default-provider algorithm
    /// descriptor registration path â€” the simplest construction matches the
    /// C behaviour of `ossl_dsa_newctx()` at `dsa_sig.c` line 160 which also
    /// inherits the library context from the default provider.
    #[must_use]
    pub fn new(variant: DsaVariant) -> Self {
        Self {
            variant,
            lib_ctx: LibContext::get_default(),
            propq: None,
        }
    }

    /// Creates a new provider bound to an explicit library context and
    /// property query.
    ///
    /// Callers that operate multiple isolated library contexts (e.g. FIPS
    /// vs. non-FIPS) use this constructor to scope the DSA provider to a
    /// specific [`LibContext`].  The `propq` argument is forwarded verbatim
    /// to every spawned signature context and becomes the property query
    /// passed to [`MessageDigest::fetch`].
    #[must_use]
    pub fn new_with_context(
        variant: DsaVariant,
        lib_ctx: Arc<LibContext>,
        propq: Option<String>,
    ) -> Self {
        Self {
            variant,
            lib_ctx,
            propq,
        }
    }

    /// Returns the algorithm variant this provider was configured for.
    #[inline]
    #[must_use]
    pub fn variant(&self) -> DsaVariant {
        self.variant
    }
}

impl SignatureProvider for DsaSignatureProvider {
    /// Returns the canonical algorithm name for the bound variant.  Matches
    /// the primary `PROV_NAMES_*` entries registered in `defltprov.c`.
    fn name(&self) -> &'static str {
        self.variant.name()
    }

    /// Allocates a fresh [`DsaSignatureContext`] bound to this provider's
    /// variant, library context and property query.
    ///
    /// Each call yields a brand-new context â€” no state is ever shared
    /// between contexts, satisfying **Rule R7**.  The heap box keeps the
    /// implementation type erased at the trait-object level, mirroring the
    /// opaque `void *provctx` returned by `ossl_dsa_newctx()`.
    fn new_ctx(&self) -> ProviderResult<Box<dyn SignatureContext>> {
        debug!(
            algorithm = self.variant.name(),
            is_sigalg = self.variant.is_sigalg(),
            has_propq = self.propq.is_some(),
            "dsa: creating new signature context"
        );

        Ok(Box::new(DsaSignatureContext::new(
            self.variant,
            Arc::clone(&self.lib_ctx),
            self.propq.clone(),
        )))
    }
}

// =============================================================================
// Inherent parameter handling â€” set_ctx_params / get_ctx_params
//
// These are the C-parity names from `dsa_sig.c` (`dsa_set_ctx_params` and
// `dsa_get_ctx_params` at lines ~770â€“900).  The [`SignatureContext`] trait
// methods [`SignatureContext::set_params`] and [`SignatureContext::get_params`]
// delegate to these inherent helpers so internal callers can keep using the
// familiar C-style names while the trait surface remains the external API.
// =============================================================================

impl DsaSignatureContext {
    /// Applies a parameter set to this context.  This mirrors
    /// `dsa_set_ctx_params()` from `dsa_sig.c` line ~770.
    ///
    /// Supported parameters:
    ///
    /// * `"digest"` â€” UTF-8 string.  Selects the hash algorithm used by
    ///   digest-sign/verify.  On composable DSA the digest is freely
    ///   settable until the first `sign` or `verify` call; on a fixed
    ///   sigalg it must match the baked-in variant (any mismatch yields
    ///   [`ProviderError::Common`] with
    ///   [`openssl_common::CommonError::InvalidArgument`]).
    /// * `"properties"` â€” UTF-8 string.  Updates the property query used
    ///   when fetching message digests.  The fresh query replaces any
    ///   previously-stored query verbatim.
    /// * `"nonce-type"` â€” unsigned 64-bit integer (`ParamValue::UInt64`).
    ///   `0` â†’ [`NonceType::Default`] (random), `1` â†’ [`NonceType::Deterministic`]
    ///   (RFC 6979).  The crypto layer currently implements only the
    ///   random variant; selecting deterministic signing will surface
    ///   [`ProviderError::AlgorithmUnavailable`] on the next sign call.
    /// * `"signature"` â€” octet string.  Cached signature used by the
    ///   verify-message flow so a single context can hold both the
    ///   to-be-verified message and its signature.  Handed to
    ///   [`DsaSignatureContext::cached_signature`].
    ///
    /// Unknown parameters are ignored â€” this matches the C behaviour of
    /// iterating over the supplied `OSSL_PARAM` array and silently
    /// skipping entries whose key was not recognised.
    ///
    /// # Errors
    ///
    /// * [`ProviderError::Common`] wrapping
    ///   [`openssl_common::CommonError::ParamTypeMismatch`] if a recognised
    ///   key is supplied with a value of the wrong shape.
    /// * [`ProviderError::Common`] with
    ///   [`openssl_common::CommonError::InvalidArgument`] if the caller
    ///   asks for a digest incompatible with the active variant.
    /// * [`ProviderError::Dispatch`] on digest fetch failure.
    pub fn set_ctx_params(&mut self, params: &ParamSet) -> ProviderResult<()> {
        if params.is_empty() {
            return Ok(());
        }

        trace!(
            algorithm = self.variant.name(),
            param_count = params.len(),
            "dsa: set_ctx_params"
        );

        // --- digest ---
        // `OSSL_SIGNATURE_PARAM_DIGEST` from `include/openssl/core_names.h`.
        // The C source handles this in `dsa_set_ctx_params()` at the
        // `OSSL_SIGNATURE_PARAM_DIGEST` branch (`dsa_sig.c` ~790).
        if let Some(val) = params.get("digest") {
            let name = val.as_str().ok_or_else(|| {
                ProviderError::Common(openssl_common::CommonError::ParamTypeMismatch {
                    key: "digest".to_string(),
                    expected: "Utf8String",
                    actual: val.param_type_name(),
                })
            })?;

            // Fixed sigalgs refuse caller-supplied digest changes â€” mirrors
            // the `ctx->flag_allow_md == 0` branch in the C source which
            // returns `ERR_R_PROV_LIB` with `ERR_R_PASSED_INVALID_ARGUMENT`.
            self.enforce_fixed_digest(name)?;
            self.setup_digest(name)?;
        }

        // --- properties (propquery) ---
        // `OSSL_SIGNATURE_PARAM_PROPERTIES` from
        // `include/openssl/core_names.h`.  Stored as an optional string.
        if let Some(val) = params.get("properties") {
            let propq_str = val.as_str().ok_or_else(|| {
                ProviderError::Common(openssl_common::CommonError::ParamTypeMismatch {
                    key: "properties".to_string(),
                    expected: "Utf8String",
                    actual: val.param_type_name(),
                })
            })?;

            // An empty string clears the query so callers can revert to
            // the default provider search behaviour.
            self.propq = if propq_str.is_empty() {
                None
            } else {
                Some(propq_str.to_string())
            };
            trace!(
                algorithm = self.variant.name(),
                has_propq = self.propq.is_some(),
                "dsa: propq updated via set_ctx_params"
            );
        }

        // --- nonce-type ---
        // `OSSL_SIGNATURE_PARAM_NONCE_TYPE` from
        // `include/openssl/core_names.h`.  C uses an `OSSL_PARAM_UINT`
        // which we map to `ParamValue::UInt64` for a lossless round-trip.
        if let Some(val) = params.get("nonce-type") {
            let raw = val.as_u64().ok_or_else(|| {
                ProviderError::Common(openssl_common::CommonError::ParamTypeMismatch {
                    key: "nonce-type".to_string(),
                    expected: "UInt64",
                    actual: val.param_type_name(),
                })
            })?;
            let new_nonce = NonceType::from_raw(raw).map_err(ProviderError::Common)?;
            if new_nonce != self.nonce_type {
                debug!(
                    algorithm = self.variant.name(),
                    from = ?self.nonce_type,
                    to = ?new_nonce,
                    "dsa: nonce-type changed via set_ctx_params"
                );
                self.nonce_type = new_nonce;
            }
        }

        // --- signature (cached for verify-message flow) ---
        // `OSSL_SIGNATURE_PARAM_SIGNATURE` from
        // `include/openssl/core_names.h`.  See `dsa_sig.c` ~840.
        if let Some(val) = params.get("signature") {
            let sig_bytes = val.as_bytes().ok_or_else(|| {
                ProviderError::Common(openssl_common::CommonError::ParamTypeMismatch {
                    key: "signature".to_string(),
                    expected: "OctetString",
                    actual: val.param_type_name(),
                })
            })?;
            // Scrub any previously cached signature before overwriting.
            if let Some(prev) = self.cached_signature.as_mut() {
                prev.zeroize();
            }
            self.cached_signature = Some(sig_bytes.to_vec());
            trace!(
                algorithm = self.variant.name(),
                sig_len = sig_bytes.len(),
                "dsa: cached_signature updated via set_ctx_params"
            );
        }

        Ok(())
    }

    /// Builds a parameter set describing the current context state.  This
    /// mirrors `dsa_get_ctx_params()` from `dsa_sig.c` line ~870.
    ///
    /// The returned [`ParamSet`] contains the following keys:
    ///
    /// * `"algorithm-id"` â€” DER-encoded `AlgorithmIdentifier` for the
    ///   current variant (and active digest, for composable DSA).  Cached
    ///   lazily in [`DsaSignatureContext::aid_cache`] so repeated calls are
    ///   cheap.
    /// * `"digest"` â€” the canonical digest name currently bound to the
    ///   context.  Absent until a digest has been selected on composable
    ///   DSA; always populated on fixed sigalgs (the variant's baked-in
    ///   digest).
    /// * `"nonce-type"` â€” the active nonce selector (`0` = random,
    ///   `1` = deterministic).
    pub fn get_ctx_params(&mut self) -> ProviderResult<ParamSet> {
        let mut out = ParamSet::new();

        // --- algorithm-id (lazy) ---
        if self.aid_cache.is_none() {
            self.aid_cache = Some(self.compute_aid());
        }
        if let Some(aid) = self.aid_cache.as_ref() {
            out.set("algorithm-id", ParamValue::OctetString(aid.clone()));
        }

        // --- digest name ---
        // Fixed sigalgs always have a digest even if the caller never
        // called setup_digest â€” surface the baked-in one.
        if let Some(name) = self.md_name.as_ref() {
            out.set("digest", ParamValue::Utf8String(name.clone()));
        } else if let Some(fixed) = self.variant.fixed_digest() {
            out.set("digest", ParamValue::Utf8String(fixed.to_string()));
        }

        // --- nonce-type ---
        out.set("nonce-type", ParamValue::UInt64(self.nonce_type.as_raw()));

        Ok(out)
    }
}

// =============================================================================
// Shared sign / verify primitives â€” inherent helpers
// =============================================================================
//
// These helpers consolidate the call into the `openssl-crypto` DSA primitive
// so that the one-shot trait methods (`sign` / `verify`) and the streaming
// trait methods (`digest_sign_final` / `digest_verify_final`) share a single
// source of truth.  In the C provider, `dsa_sign_int()` and `dsa_verify_int()`
// play the same role (`dsa_sig.c` ~170 and ~330).
//
// The key insight is that the DSA signing primitive always operates on a
// **pre-computed digest** â€” not on the raw message.  The streaming variants
// hash the accumulated buffer first and then delegate here.
impl DsaSignatureContext {
    /// Signs a pre-computed `digest` using the private key bound to this
    /// context.
    ///
    /// Shared by both the one-shot [`SignatureContext::sign`] entry point
    /// (which receives a digest directly) and the streaming
    /// [`SignatureContext::digest_sign_final`] entry point (which receives a
    /// hash of the accumulated streaming buffer).
    ///
    /// The produced signature is cached in
    /// [`DsaSignatureContext::cached_signature`] so the higher-level
    /// verify-message flow (TLS 1.3 CertificateVerify-style) can retrieve it
    /// via `get_ctx_params("signature")`.
    ///
    /// # Errors
    ///
    /// * [`ProviderError::AlgorithmUnavailable`] if the configured nonce
    ///   selector is unsupported (e.g. deterministic nonces).
    /// * [`ProviderError::Init`] if no private key is bound.
    /// * [`ProviderError::Dispatch`] if the underlying crypto primitive
    ///   reports an error.
    fn sign_digest(&mut self, digest: &[u8]) -> ProviderResult<Vec<u8>> {
        // Honour the nonce-type gate â€” deterministic nonces are a
        // first-class configuration that must be flagged if unsupported.
        self.require_supported_nonce("sign")?;

        // Clone the Arc so we release the immutable borrow on `self`
        // before mutably touching `cached_signature`.
        let private_key_arc = Arc::clone(self.require_private_key("sign_digest")?);

        trace!(
            algorithm = self.variant.name(),
            digest_len = digest.len(),
            "dsa: sign_digest invoking crypto primitive"
        );

        let signature = dsa_sign_primitive(private_key_arc.as_ref(), digest)
            .map_err(|e| map_crypto_sign_error(&e))?;

        // Scrub any previously cached signature before overwriting â€” the
        // slot is long-lived across calls and we must not leak residues
        // between invocations.
        if let Some(prev) = self.cached_signature.as_mut() {
            prev.zeroize();
        }
        self.cached_signature = Some(signature.clone());

        Ok(signature)
    }

    /// Verifies `signature` against the pre-computed `digest` using the
    /// public key bound to this context.
    ///
    /// Shared by both the one-shot [`SignatureContext::verify`] and the
    /// streaming [`SignatureContext::digest_verify_final`] entry points.
    ///
    /// Takes `&self` because verification does not mutate context state â€”
    /// the cached-signature slot is only touched on signing.
    ///
    /// # Errors
    ///
    /// * [`ProviderError::Init`] if no public key is bound.
    /// * [`ProviderError::Dispatch`] if the underlying crypto primitive
    ///   reports an error.  A well-formed signature that simply fails
    ///   cryptographic verification returns `Ok(false)`, not an error.
    fn verify_digest(&self, digest: &[u8], signature: &[u8]) -> ProviderResult<bool> {
        let public_key_arc = self.require_public_key("verify_digest")?;

        trace!(
            algorithm = self.variant.name(),
            digest_len = digest.len(),
            sig_len = signature.len(),
            "dsa: verify_digest invoking crypto primitive"
        );

        dsa_verify_primitive(public_key_arc.as_ref(), digest, signature)
            .map_err(|e| map_crypto_verify_error(&e))
    }
}

// =============================================================================
// SignatureContext trait implementation
// =============================================================================
//
// This impl block covers the full DSA operation lifecycle:
//
// * One-shot sign/verify (`sign_init` â†’ `sign`, `verify_init` â†’ `verify`) â€”
//   caller supplies a pre-hashed digest.
// * Streaming digest-sign/verify (`digest_sign_init` â†’
//   `digest_sign_update`* â†’ `digest_sign_final`, and verify counterparts) â€”
//   caller feeds raw message bytes, the provider hashes them internally.
// * Parameter get/set â€” forwards to the inherent `get_ctx_params` /
//   `set_ctx_params` methods.
//
// The lifecycle mirrors the C provider's `dsa_sign_init` / `dsa_sign` /
// `dsa_digest_sign_init` / `dsa_digest_sign_update` /
// `dsa_digest_sign_final` dispatch functions from `dsa_sig.c`.
impl SignatureContext for DsaSignatureContext {
    // -------------------------------------------------------------------
    // one-shot sign / verify
    // -------------------------------------------------------------------

    /// Initialises the context for signing.
    ///
    /// Mirrors `dsa_sign_init()` from `dsa_sig.c` ~220.  Parses the
    /// TLV-encoded private-key blob, closes the streaming gates (this is
    /// the one-shot flow), wipes any residual state, and applies caller-
    /// supplied parameters.  Fixed sigalgs automatically bind their
    /// baked-in digest so subsequent `get_params()` calls return the
    /// correct `AlgorithmIdentifier`.
    fn sign_init(&mut self, key: &[u8], params: Option<&ParamSet>) -> ProviderResult<()> {
        debug!(
            algorithm = self.variant.name(),
            key_len = key.len(),
            has_params = params.is_some(),
            "dsa: sign_init"
        );

        // Parse the TLV-encoded key blob into domain params + private x.
        let decoded = parse_dsa_key(key)?;
        self.install_private_key(decoded)?;

        // One-shot sign flow: the streaming entry points must remain
        // closed until the caller explicitly switches to the digest-sign
        // variant via digest_sign_init.
        self.operation = Some(OperationMode::Sign);
        self.allow_update = false;
        self.allow_final = false;

        // Wipe any residual streaming state from a previous operation.
        self.streaming_buffer.clear();
        self.md_ctx = None;
        if let Some(prev) = self.cached_signature.as_mut() {
            prev.zeroize();
        }
        self.cached_signature = None;

        // Apply caller-supplied parameters (digest name, propquery,
        // nonce-type, cached signature) if any.  Fixed sigalgs reject
        // attempts to change the digest via the fixed-sigalg guard in
        // set_ctx_params â†’ enforce_fixed_digest.
        if let Some(p) = params {
            self.set_ctx_params(p)?;
        }

        // Fixed sigalgs always bind the baked-in digest â€” this also
        // primes md_name so the AlgorithmIdentifier cache reflects the
        // correct combination in subsequent get_params() calls.
        if let Some(fixed) = self.variant.fixed_digest() {
            self.setup_digest(fixed)?;
        }

        Ok(())
    }

    /// Signs the pre-hashed `data`.
    ///
    /// Per the trait contract, `data` IS the pre-computed digest (not the
    /// raw message).  We hand it directly to the DSA signing primitive
    /// without re-hashing.  The C dispatch `dsa_sign` in `dsa_sig.c` ~240
    /// exhibits the same behaviour: it assumes a caller-supplied digest
    /// and delegates to `DSA_sign()` which operates on raw digest bytes.
    fn sign(&mut self, data: &[u8]) -> ProviderResult<Vec<u8>> {
        self.require_operation(OperationMode::Sign, "sign")?;
        self.sign_digest(data)
    }

    /// Initialises the context for verification.
    ///
    /// Symmetric counterpart to [`Self::sign_init`] â€” parses the public
    /// key, closes the streaming gates, wipes residual state, and applies
    /// caller-supplied parameters.  Cached signatures (set via
    /// `set_ctx_params("signature", ...)`) are preserved so they can be
    /// reused by the `verify_message_final` flow.
    fn verify_init(&mut self, key: &[u8], params: Option<&ParamSet>) -> ProviderResult<()> {
        debug!(
            algorithm = self.variant.name(),
            key_len = key.len(),
            has_params = params.is_some(),
            "dsa: verify_init"
        );

        let decoded = parse_dsa_key(key)?;
        self.install_public_key(decoded)?;

        self.operation = Some(OperationMode::Verify);
        self.allow_update = false;
        self.allow_final = false;

        self.streaming_buffer.clear();
        self.md_ctx = None;

        if let Some(p) = params {
            self.set_ctx_params(p)?;
        }

        if let Some(fixed) = self.variant.fixed_digest() {
            self.setup_digest(fixed)?;
        }

        Ok(())
    }

    /// Verifies `signature` against the pre-hashed `data`.
    ///
    /// As with [`Self::sign`], `data` is the pre-computed digest.
    /// Mirrors `dsa_verify()` in `dsa_sig.c` ~330.
    fn verify(&mut self, data: &[u8], signature: &[u8]) -> ProviderResult<bool> {
        self.require_operation(OperationMode::Verify, "verify")?;
        self.verify_digest(data, signature)
    }

    // -------------------------------------------------------------------
    // streaming digest-sign / digest-verify
    // -------------------------------------------------------------------

    /// Initialises a streaming digest-sign operation bound to the named
    /// digest algorithm.
    ///
    /// Mirrors `dsa_digest_sign_init()` in `dsa_sig.c` ~560.  The
    /// `digest` name is canonicalised (e.g. `"sha-256"` â†’ `"SHA256"`) and
    /// fetched from the provider store; XOF digests (SHAKE*) are
    /// rejected because DSA signing requires a fixed-output hash.
    ///
    /// For fixed sigalgs (`DSA-SHA256`, etc.), the caller-supplied
    /// `digest` must match the sigalg's baked-in hash â€” otherwise
    /// [`ProviderError::Common`] is returned.
    fn digest_sign_init(
        &mut self,
        digest: &str,
        key: &[u8],
        params: Option<&ParamSet>,
    ) -> ProviderResult<()> {
        debug!(
            algorithm = self.variant.name(),
            digest = digest,
            key_len = key.len(),
            has_params = params.is_some(),
            "dsa: digest_sign_init"
        );

        // Fixed sigalgs reject caller-supplied digest overrides.
        self.enforce_fixed_digest(digest)?;

        let decoded = parse_dsa_key(key)?;
        self.install_private_key(decoded)?;

        self.operation = Some(OperationMode::Sign);
        // Streaming flow: open update/final gates until final is called.
        self.allow_update = true;
        self.allow_final = true;

        // Reset streaming buffer, cached signature, and digest context
        // for a clean start.
        self.streaming_buffer.clear();
        self.md_ctx = None;
        if let Some(prev) = self.cached_signature.as_mut() {
            prev.zeroize();
        }
        self.cached_signature = None;

        if let Some(p) = params {
            self.set_ctx_params(p)?;
        }

        // Bind the caller-supplied digest (or the fixed one â€” the
        // enforce_fixed_digest call above guarantees they match for
        // sigalgs).
        self.setup_digest(digest)?;

        Ok(())
    }

    /// Feeds raw message bytes into the running digest-sign computation.
    ///
    /// We accumulate the raw bytes into `streaming_buffer` and defer the
    /// actual hashing to [`Self::digest_sign_final`].  This mirrors the C
    /// `dsa_signverify_message_update()` dispatch which also defers the
    /// `EVP_DigestUpdate` chain to the final call to preserve flexibility
    /// on error paths.  It also honours Rule R7 (no shared mutable state
    /// across operations): the `MdContext` is only instantiated in final
    /// for the lifetime of the hash.
    fn digest_sign_update(&mut self, data: &[u8]) -> ProviderResult<()> {
        trace!(
            algorithm = self.variant.name(),
            data_len = data.len(),
            "dsa: digest_sign_update"
        );
        self.require_operation(OperationMode::Sign, "digest_sign_update")?;
        if !self.allow_update {
            return Err(ProviderError::Init(
                "dsa: digest_sign_update called outside a streaming sign flow (use digest_sign_init first)".to_string(),
            ));
        }
        self.streaming_buffer.extend_from_slice(data);
        Ok(())
    }

    /// Finalises the digest-sign computation.
    ///
    /// Hashes the accumulated `streaming_buffer` with the bound digest,
    /// securely wipes the raw message bytes, and forwards the hash to the
    /// DSA signing primitive via [`Self::sign_digest`].  Mirrors
    /// `dsa_sign_message_final()` in `dsa_sig.c` ~660.
    ///
    /// Closes the update/final gates on success so repeated calls return
    /// [`ProviderError::Init`] instead of signing a zero-length message.
    fn digest_sign_final(&mut self) -> ProviderResult<Vec<u8>> {
        debug!(
            algorithm = self.variant.name(),
            buffer_len = self.streaming_buffer.len(),
            "dsa: digest_sign_final"
        );
        self.require_operation(OperationMode::Sign, "digest_sign_final")?;
        if !self.allow_final {
            return Err(ProviderError::Init(
                "dsa: digest_sign_final called without a prior digest_sign_init".to_string(),
            ));
        }

        // Pull the message bytes out of the context so we can zeroize
        // them after hashing â€” the digest itself is all we need for
        // signing and we must not leave plaintext message residues in
        // the context.
        let message = std::mem::take(&mut self.streaming_buffer);

        let md = self.md.clone().ok_or_else(|| {
            ProviderError::Init("dsa: digest_sign_final called without a bound digest".to_string())
        })?;

        let digest_bytes = digest_one_shot(&md, &message).map_err(map_crypto_digest_error)?;

        // Scrub the raw message bytes â€” they may have contained
        // sensitive caller data.
        let mut spent = message;
        spent.zeroize();

        // Close the gates so repeated calls error out cleanly.
        self.allow_update = false;
        self.allow_final = false;

        self.sign_digest(&digest_bytes)
    }

    /// Initialises a streaming digest-verify operation bound to the
    /// named digest algorithm.
    ///
    /// Symmetric counterpart to [`Self::digest_sign_init`].  Mirrors
    /// `dsa_digest_verify_init()` in `dsa_sig.c` ~600.
    fn digest_verify_init(
        &mut self,
        digest: &str,
        key: &[u8],
        params: Option<&ParamSet>,
    ) -> ProviderResult<()> {
        debug!(
            algorithm = self.variant.name(),
            digest = digest,
            key_len = key.len(),
            has_params = params.is_some(),
            "dsa: digest_verify_init"
        );

        self.enforce_fixed_digest(digest)?;

        let decoded = parse_dsa_key(key)?;
        self.install_public_key(decoded)?;

        self.operation = Some(OperationMode::Verify);
        self.allow_update = true;
        self.allow_final = true;

        self.streaming_buffer.clear();
        self.md_ctx = None;

        if let Some(p) = params {
            self.set_ctx_params(p)?;
        }

        self.setup_digest(digest)?;

        Ok(())
    }

    /// Feeds raw message bytes into the running digest-verify computation.
    fn digest_verify_update(&mut self, data: &[u8]) -> ProviderResult<()> {
        trace!(
            algorithm = self.variant.name(),
            data_len = data.len(),
            "dsa: digest_verify_update"
        );
        self.require_operation(OperationMode::Verify, "digest_verify_update")?;
        if !self.allow_update {
            return Err(ProviderError::Init(
                "dsa: digest_verify_update called outside a streaming verify flow (use digest_verify_init first)".to_string(),
            ));
        }
        self.streaming_buffer.extend_from_slice(data);
        Ok(())
    }

    /// Finalises the digest-verify computation by hashing the accumulated
    /// buffer and comparing against `signature`.
    ///
    /// Mirrors `dsa_digest_verify_final()` in `dsa_sig.c` ~640.
    fn digest_verify_final(&mut self, signature: &[u8]) -> ProviderResult<bool> {
        debug!(
            algorithm = self.variant.name(),
            buffer_len = self.streaming_buffer.len(),
            sig_len = signature.len(),
            "dsa: digest_verify_final"
        );
        self.require_operation(OperationMode::Verify, "digest_verify_final")?;
        if !self.allow_final {
            return Err(ProviderError::Init(
                "dsa: digest_verify_final called without a prior digest_verify_init".to_string(),
            ));
        }

        let message = std::mem::take(&mut self.streaming_buffer);

        let md = self.md.clone().ok_or_else(|| {
            ProviderError::Init(
                "dsa: digest_verify_final called without a bound digest".to_string(),
            )
        })?;

        let digest_bytes = digest_one_shot(&md, &message).map_err(map_crypto_digest_error)?;

        let mut spent = message;
        spent.zeroize();

        self.allow_update = false;
        self.allow_final = false;

        self.verify_digest(&digest_bytes, signature)
    }

    // -------------------------------------------------------------------
    // parameter get / set
    // -------------------------------------------------------------------

    /// Returns a [`ParamSet`] describing the current context state.
    ///
    /// The `&self` signature prevents this variant from caching the AID
    /// (the inherent [`Self::get_ctx_params`] method does that via
    /// `&mut self`).  Instead, we clone the cached AID if present or
    /// compute a fresh one on each call â€” cheap because the AID is a
    /// short DER blob (â‰¤13 bytes for DSA).
    ///
    /// The returned set contains:
    ///
    /// * `"algorithm-id"` â€” DER-encoded `AlgorithmIdentifier` for the
    ///   current variant and active digest.
    /// * `"digest"` â€” canonical digest name (absent until set on
    ///   composable DSA; always present on fixed sigalgs).
    /// * `"nonce-type"` â€” the active nonce selector (`0` = random,
    ///   `1` = deterministic).
    fn get_params(&self) -> ProviderResult<ParamSet> {
        let mut out = ParamSet::new();

        // --- algorithm-id ---
        // Clone if cached, otherwise compute on the fly.  compute_aid is
        // pure and cheap â€” it performs a variant match and copies a
        // small byte literal.
        let aid = self.aid_cache.clone().unwrap_or_else(|| self.compute_aid());
        out.set("algorithm-id", ParamValue::OctetString(aid));

        // --- digest name ---
        // Fixed sigalgs always have a digest even if the caller never
        // called setup_digest â€” surface the baked-in one.
        if let Some(name) = self.md_name.as_ref() {
            out.set("digest", ParamValue::Utf8String(name.clone()));
        } else if let Some(fixed) = self.variant.fixed_digest() {
            out.set("digest", ParamValue::Utf8String(fixed.to_string()));
        }

        // --- nonce-type ---
        out.set("nonce-type", ParamValue::UInt64(self.nonce_type.as_raw()));

        Ok(out)
    }

    /// Applies context parameters from the supplied [`ParamSet`].
    ///
    /// Delegates to the inherent [`Self::set_ctx_params`] which is the
    /// authoritative implementation â€” this trait wrapper exists so that
    /// generic dispatch over `dyn SignatureContext` works uniformly.
    fn set_params(&mut self, params: &ParamSet) -> ProviderResult<()> {
        self.set_ctx_params(params)
    }
}

// =============================================================================
// Export-schema inherent methods: sign_message_* / verify_message_*
// =============================================================================
//
// The AAP export schema for `DsaSignatureContext` exposes four additional
// entry points beyond the trait surface:
//
// * `sign_message_update()` / `sign_message_final()`
// * `verify_message_update()` / `verify_message_final()`
//
// These mirror the C provider's `dsa_signverify_message_update()`,
// `dsa_sign_message_final()`, and `dsa_verify_message_final()` dispatch
// entries (`dsa_sig.c` ~710â€“770).  They are inherent `pub fn`s rather than
// trait methods because the trait abstraction models the streaming flow
// through `digest_sign_*` / `digest_verify_*`; the C "message" flow is a
// thin wrapper that happens to reuse the same buffering logic.
//
// The distinguishing feature of the "message" verify flow is that the
// signature being verified is retrieved from the context's cached
// signature slot (populated via `set_ctx_params("signature", ...)`) rather
// than passed as a parameter.  This is the TLS 1.3 CertificateVerify
// pattern used when the caller has configured the signature out-of-band.
impl DsaSignatureContext {
    /// Inherent counterpart of [`SignatureContext::digest_sign_update`]
    /// exposed through the export schema.
    ///
    /// Mirrors `dsa_signverify_message_update()` from `dsa_sig.c` ~710
    /// for the sign case.  Delegates to the trait implementation for a
    /// single source of truth.
    pub fn sign_message_update(&mut self, data: &[u8]) -> ProviderResult<()> {
        <Self as SignatureContext>::digest_sign_update(self, data)
    }

    /// Inherent counterpart of [`SignatureContext::digest_sign_final`]
    /// exposed through the export schema.
    ///
    /// Mirrors `dsa_sign_message_final()` from `dsa_sig.c` ~730.
    pub fn sign_message_final(&mut self) -> ProviderResult<Vec<u8>> {
        <Self as SignatureContext>::digest_sign_final(self)
    }

    /// Inherent counterpart of [`SignatureContext::digest_verify_update`]
    /// exposed through the export schema.
    ///
    /// Mirrors `dsa_signverify_message_update()` from `dsa_sig.c` ~710
    /// for the verify case.
    pub fn verify_message_update(&mut self, data: &[u8]) -> ProviderResult<()> {
        <Self as SignatureContext>::digest_verify_update(self, data)
    }

    /// Inherent `verify_message_final` entry point.
    ///
    /// Unlike [`SignatureContext::digest_verify_final`], this variant does
    /// **not** accept a signature argument.  Instead it retrieves the
    /// cached signature previously set via
    /// `set_ctx_params("signature", ...)` â€” this is the TLS 1.3
    /// `CertificateVerify` pattern used when the signature has been
    /// configured out-of-band.
    ///
    /// Mirrors `dsa_verify_message_final()` from `dsa_sig.c` ~760.
    ///
    /// # Errors
    ///
    /// [`ProviderError::Init`] if no cached signature is present on the
    /// context.  Callers must set the signature via
    /// `set_ctx_params("signature", ...)` prior to invoking this method.
    pub fn verify_message_final(&mut self) -> ProviderResult<bool> {
        // Retrieve the caller-supplied signature from the cache slot.
        let sig = self.cached_signature.clone().ok_or_else(|| {
            ProviderError::Init(
                "dsa: verify_message_final called without a cached signature â€” \
                 set one via set_ctx_params(\"signature\", ...) first"
                    .to_string(),
            )
        })?;
        <Self as SignatureContext>::digest_verify_final(self, &sig)
    }
}

// =============================================================================
// Algorithm descriptors
//
// Every fixed digest sigalg dispatch table produced by the
// `IMPL_DSA_SIGALG(sha1, NID_sha1, ...)` family of macros in
// `providers/implementations/signature/dsa_sig.c` lines ~950â€“1065
// has a corresponding descriptor here.  The composable DSA dispatch
// is represented by [`dsa_signature_descriptor`]; the nine fixed
// digest combinations follow in the exact canonical order used by
// `providers/implementations/include/prov/names.h` lines ~31â€“41.
//
// Algorithm names and OIDs are preserved verbatim from the C source
// via the `PROV_NAMES_DSA*` macros so consumers may look up any
// variant using the same string aliases they would use with the
// OpenSSL 3 C provider.  Note the two DSA-SHA384 / DSA-SHA512 OIDs
// retain their historical "1.2.840.1.101.3.4.3.{3,4}" prefixes â€”
// these match the OpenSSL reference headers byte-for-byte even
// though the later SHA-2 / SHA-3 variants migrated to the
// "2.16.840.1.101.3.4.3.{1..8}" family.
//
// Consumer: [`crate::implementations::signatures::descriptors`],
// which aggregates descriptors from every signature implementation
// (DSA, ECDSA, EdDSA, ML-DSA, RSA, SLH-DSA, SM2, LMS).  The
// composable DSA descriptor appears first, followed by the nine
// digest-bound sigalgs ordered by digest strength (SHA1 â†’ SHA-2
// family â†’ SHA-3 family) to match the `IMPL_DSA_SIGALG` emission
// order in the C source.
// =============================================================================

/// Descriptor for the composable DSA signature variant.
///
/// The composable variant is the general-purpose entry point: the
/// digest is selected via `set_ctx_params("digest", ...)` and the
/// sign / verify operations may be invoked either via the pre-hashed
/// path (`sign()` / `verify()`) or the streaming path (`digest_sign_*`
/// / `digest_verify_*`).  This descriptor corresponds to the
/// `ossl_dsa_signature_functions` dispatch table at
/// `dsa_sig.c` line ~932.
///
/// Algorithm names include the canonical "DSA", the legacy
/// "dsaEncryption" OID text form (per PKCS #1 historical usage),
/// and the "1.2.840.10040.4.1" dotted-decimal OID â€” the exact
/// alias list from `PROV_NAMES_DSA` in `names.h`.
#[must_use]
pub fn dsa_signature_descriptor() -> AlgorithmDescriptor {
    algorithm(
        &["DSA", "dsaEncryption", "1.2.840.10040.4.1"],
        "provider=default",
        "OpenSSL DSA implementation",
    )
}

/// Descriptor for the fixed DSA-with-SHA1 sigalg variant.
///
/// The digest is bound to SHA-1 at provider-fetch time â€” callers
/// cannot override it via `set_ctx_params("digest", ...)`.  This
/// descriptor corresponds to the `ossl_dsa_sha1_signature_functions`
/// dispatch table at `dsa_sig.c` produced by
/// `IMPL_DSA_SIGALG(sha1, NID_dsaWithSHA1, ...)`.
///
/// Name aliases are preserved from `PROV_NAMES_DSA_SHA1` in
/// `names.h`: "DSA-SHA1", the legacy hyphenated "DSA-SHA-1",
/// the camelCase "dsaWithSHA1", and the "1.2.840.10040.4.3" OID.
#[must_use]
pub fn dsa_sha1_signature_descriptor() -> AlgorithmDescriptor {
    algorithm(
        &["DSA-SHA1", "DSA-SHA-1", "dsaWithSHA1", "1.2.840.10040.4.3"],
        "provider=default",
        "OpenSSL DSA with SHA-1 implementation",
    )
}

