/// Produced by `IMPL_DSA_SIGALG(sha224, NID_dsa_with_SHA224, ...)`
/// in `dsa_sig.c`.  Aliases from `PROV_NAMES_DSA_SHA224` in
/// `names.h`: primary "DSA-SHA2-224", legacy "DSA-SHA224",
/// `snake_case` `"dsa_with_SHA224"`, OID "2.16.840.1.101.3.4.3.1".
#[must_use]
pub fn dsa_sha224_signature_descriptor() -> AlgorithmDescriptor {
    algorithm(
        &[
            "DSA-SHA2-224",
            "DSA-SHA224",
            "dsa_with_SHA224",
            "2.16.840.1.101.3.4.3.1",
        ],
        "provider=default",
        "OpenSSL DSA with SHA-2-224 implementation",
    )
}

