/// Returns every DSA algorithm descriptor exposed by this module.
///
/// Order is deterministic and matches the canonical reference order
/// established by the `IMPL_DSA_SIGALG` instantiation sequence at
/// the bottom of `dsa_sig.c`: the composable DSA variant first,
/// followed by the nine fixed digest sigalgs in digest-strength
/// order (SHA-1 â†’ SHA-2 family ascending â†’ SHA-3 family ascending).
/// Consumers â€” notably [`crate::implementations::signatures::descriptors`] â€”
/// rely on this ordering for stable provider fingerprints and
/// algorithm enumeration reproducibility across process restarts.
///
/// Returned [`AlgorithmDescriptor`] values are cheap to clone and
/// bear no lifetime tying them to the library context; they may
/// be aggregated or filtered freely.
#[must_use]
pub fn descriptors() -> Vec<AlgorithmDescriptor> {
    vec![
        dsa_signature_descriptor(),
        dsa_sha1_signature_descriptor(),
        dsa_sha224_signature_descriptor(),
        dsa_sha256_signature_descriptor(),
        dsa_sha384_signature_descriptor(),
        dsa_sha512_signature_descriptor(),
        dsa_sha3_224_signature_descriptor(),
        dsa_sha3_256_signature_descriptor(),
        dsa_sha3_384_signature_descriptor(),
        dsa_sha3_512_signature_descriptor(),
    ]
}

// =============================================================================
// Tests
// =============================================================================

// Rationale: Tests intentionally use unwrap/expect/panic to fail fast on
// unexpected errors. The workspace-wide `unwrap_used` and `expect_used` lints
// are documented in the root `Cargo.toml` as applying to library code only â€”
// "Tests and CLI main() may #[allow] with justification." Panics trigger
// automatic test failure with a clear backtrace, which is exactly the desired
// diagnostic behaviour in unit tests. `clippy::unwrap_used` covers both
// `unwrap()` and `unwrap_err()`; `clippy::expect_used` covers both `expect()`
// and `expect_err()`.
#[cfg(test)]
#[allow(
    clippy::unwrap_used,
    clippy::expect_used,
    clippy::panic,
    clippy::missing_panics_doc
)]
mod tests {
    use super::*;

    // -------------------------------------------------------------------------
    // NonceType surface
    // -------------------------------------------------------------------------

    #[test]
    fn nonce_type_default_variant_is_default() {
        // The C source uses 0 as the sentinel for random-k nonce, which in
        // Rust maps to `NonceType::Default` as the `impl Default` result.
        let n: NonceType = NonceType::default();
        assert_eq!(n, NonceType::Default);
    }

    #[test]
    fn nonce_type_round_trip_through_raw() {
        // Verify that every variant round-trips through the `as_raw` /
        // `from_raw` boundary used by the `"nonce-type"` OSSL parameter.
        for variant in [NonceType::Default, NonceType::Deterministic] {
            let raw = variant.as_raw();
            let parsed = NonceType::from_raw(raw).expect("canonical raw must parse");
            assert_eq!(parsed, variant, "raw={raw}");
        }
    }

    #[test]
    fn nonce_type_raw_encoding_matches_c_source() {
        // `dsa_sig.c` uses 0 for the historical default (random-k) and 1 for
        // the RFC 6979 deterministic mode. Lock the encoding to these values
        // for ABI stability across provider version boundaries.
        assert_eq!(NonceType::Default.as_raw(), 0);
        assert_eq!(NonceType::Deterministic.as_raw(), 1);
    }

    #[test]
    fn nonce_type_rejects_unknown_values() {
        // Any non-0/1 value is rejected â€” mirrors the strict check in
        // `dsa_set_ctx_params` which ignores unrecognised nonce types.
        let err = NonceType::from_raw(2).expect_err("2 must be rejected");
        assert!(matches!(err, CommonError::InvalidArgument(_)));

        let err = NonceType::from_raw(u64::MAX).expect_err("u64::MAX must be rejected");
        assert!(matches!(err, CommonError::InvalidArgument(_)));
    }

    // -------------------------------------------------------------------------
    // DsaVariant surface
    // -------------------------------------------------------------------------

    #[test]
    fn variant_names_match_prov_names_h() {
        // These are the exact `PROV_NAMES_DSA*` primary strings from
        // `providers/implementations/include/prov/names.h`.
        assert_eq!(DsaVariant::Composable.name(), "DSA");
        assert_eq!(DsaVariant::Sha1.name(), "DSA-SHA1");
        assert_eq!(DsaVariant::Sha224.name(), "DSA-SHA224");
        assert_eq!(DsaVariant::Sha256.name(), "DSA-SHA256");
        assert_eq!(DsaVariant::Sha384.name(), "DSA-SHA384");
        assert_eq!(DsaVariant::Sha512.name(), "DSA-SHA512");
        assert_eq!(DsaVariant::Sha3_224.name(), "DSA-SHA3-224");
        assert_eq!(DsaVariant::Sha3_256.name(), "DSA-SHA3-256");
        assert_eq!(DsaVariant::Sha3_384.name(), "DSA-SHA3-384");
        assert_eq!(DsaVariant::Sha3_512.name(), "DSA-SHA3-512");
    }

    #[test]
    fn variant_is_sigalg_classification() {
        assert!(!DsaVariant::Composable.is_sigalg());
        for sigalg in [
            DsaVariant::Sha1,
            DsaVariant::Sha224,
            DsaVariant::Sha256,
            DsaVariant::Sha384,
            DsaVariant::Sha512,
            DsaVariant::Sha3_224,
            DsaVariant::Sha3_256,
            DsaVariant::Sha3_384,
            DsaVariant::Sha3_512,
        ] {
            assert!(sigalg.is_sigalg(), "variant {sigalg:?} is a sigalg");
        }
    }

    #[test]
    fn variant_fixed_digest_mapping() {
        assert_eq!(DsaVariant::Composable.fixed_digest(), None);
        assert_eq!(DsaVariant::Sha1.fixed_digest(), Some(SHA1));
        assert_eq!(DsaVariant::Sha224.fixed_digest(), Some(SHA224));
        assert_eq!(DsaVariant::Sha256.fixed_digest(), Some(SHA256));
        assert_eq!(DsaVariant::Sha384.fixed_digest(), Some(SHA384));
        assert_eq!(DsaVariant::Sha512.fixed_digest(), Some(SHA512));
        assert_eq!(DsaVariant::Sha3_224.fixed_digest(), Some(SHA3_224));
        assert_eq!(DsaVariant::Sha3_256.fixed_digest(), Some(SHA3_256));
        assert_eq!(DsaVariant::Sha3_384.fixed_digest(), Some(SHA3_384));
        assert_eq!(DsaVariant::Sha3_512.fixed_digest(), Some(SHA3_512));
    }

    // -------------------------------------------------------------------------
    // DsaSignatureProvider surface
    // -------------------------------------------------------------------------

    #[test]
    fn provider_new_preserves_variant() {
        // `new()` is the simple entry point used when the default library
        // context and no property query are desired â€” the variant must
        // survive unchanged so that `name()` reflects the requested sigalg.
        for variant in [
            DsaVariant::Composable,
            DsaVariant::Sha1,
            DsaVariant::Sha256,
            DsaVariant::Sha3_512,
        ] {
            let provider = DsaSignatureProvider::new(variant);
            assert_eq!(provider.variant(), variant);
            assert_eq!(provider.name(), variant.name());
        }
    }

    #[test]
    fn provider_name_matches_variant_name() {
        let provider = DsaSignatureProvider::new(DsaVariant::Sha256);
        assert_eq!(SignatureProvider::name(&provider), "DSA-SHA256");
    }

    #[test]
    fn provider_new_with_context_accepts_arbitrary_libctx() {
        // The variant of the constructor that explicitly takes a
        // library context and property query is used by callers that
        // isolate multiple library contexts (e.g. FIPS vs non-FIPS).
        let lib_ctx = LibContext::get_default();
        let propq = Some("provider=default".to_string());
        let provider = DsaSignatureProvider::new_with_context(
            DsaVariant::Sha256,
            Arc::clone(&lib_ctx),
            propq.clone(),
        );
        assert_eq!(provider.variant(), DsaVariant::Sha256);
        assert_eq!(provider.name(), "DSA-SHA256");
    }

    #[test]
    fn provider_new_ctx_returns_boxed_context() {
        // The trait returns `Box<dyn SignatureContext>`. Ensure the call
        // succeeds for every variant and that the returned trait object is
        // not `None` / null-equivalent.
        for variant in [
            DsaVariant::Composable,
            DsaVariant::Sha1,
            DsaVariant::Sha224,
            DsaVariant::Sha256,
            DsaVariant::Sha384,
            DsaVariant::Sha512,
            DsaVariant::Sha3_224,
            DsaVariant::Sha3_256,
            DsaVariant::Sha3_384,
            DsaVariant::Sha3_512,
        ] {
            let provider = DsaSignatureProvider::new(variant);
            let ctx = provider.new_ctx().expect("new_ctx must succeed");
            // If the trait object is valid the `get_params` call on a
            // fresh context must not panic; it may return an empty
            // parameter set (acceptable) or data describing the variant.
            let _ = ctx.get_params();
        }
    }

    // -------------------------------------------------------------------------
    // DsaSignatureContext direct surface
    // -------------------------------------------------------------------------

    #[test]
    fn context_new_has_no_key_and_no_operation() {
        // A freshly allocated context must have neither a key nor an
        // operation in progress â€” Rule R5 requires this "unset"
        // representation to be `None` rather than a sentinel.
        let ctx = DsaSignatureContext::new(DsaVariant::Composable, LibContext::get_default(), None);
        assert!(ctx.private_key.is_none());
        assert!(ctx.public_key.is_none());
        assert!(ctx.operation.is_none());
        assert!(ctx.md.is_none());
        assert!(ctx.md_name.is_none());
        assert!(ctx.md_ctx.is_none());
        assert_eq!(ctx.nonce_type, NonceType::Default);
        assert!(ctx.aid_cache.is_none());
        assert!(ctx.cached_signature.is_none());
    }

    #[test]
    fn context_composable_allows_md_change() {
        // The composable variant permits the caller to change the digest
        // before `digest_*_init`; sigalg variants do not.
        let ctx = DsaSignatureContext::new(DsaVariant::Composable, LibContext::get_default(), None);
        assert!(ctx.allow_md_change);
    }

    #[test]
    fn context_sigalg_locks_md_change() {
        // Fixed-digest sigalg variants must forbid digest changes.
        let ctx = DsaSignatureContext::new(DsaVariant::Sha256, LibContext::get_default(), None);
        assert!(!ctx.allow_md_change);
    }

    #[test]
    fn context_duplicate_preserves_variant_and_mode() {
        let ctx = DsaSignatureContext::new(
            DsaVariant::Sha384,
            LibContext::get_default(),
            Some("provider=default".to_string()),
        );
        let dup = ctx.duplicate();
        assert_eq!(dup.variant, ctx.variant);
        assert!(dup.private_key.is_none());
        assert!(dup.public_key.is_none());
        assert!(dup.operation.is_none());
        // The streaming state is intentionally reset in a duplicate â€” the
        // per-operation accumulator must not leak between contexts.
        assert!(dup.md_ctx.is_none());
        assert!(dup.streaming_buffer.is_empty());
        assert_eq!(dup.propq, ctx.propq);
    }

    #[test]
    fn context_sign_without_init_fails() {
        // Calling `sign()` before `sign_init()` must fail without
        // producing a signature â€” Rule R5 requires this operation-state
        // check rather than silently returning an empty vector. The
        // specific error kind is `Init` because `operation` is `None`,
        // indicating that `sign_init` was never invoked.
        let mut ctx =
            DsaSignatureContext::new(DsaVariant::Composable, LibContext::get_default(), None);
        let err = ctx
            .sign(b"some digest")
            .expect_err("sign before init must fail");
        assert!(
            matches!(err, ProviderError::Init(_)),
            "expected Init, got {err:?}"
        );
    }

    #[test]
    fn context_verify_without_init_fails() {
        // Parallel to `sign_without_init_fails` â€” verify must also fail
        // if `verify_init` has not been called.
        let mut ctx =
            DsaSignatureContext::new(DsaVariant::Composable, LibContext::get_default(), None);
        let err = ctx
            .verify(b"some digest", b"some signature")
            .expect_err("verify before init must fail");
        assert!(
            matches!(err, ProviderError::Init(_)),
            "expected Init, got {err:?}"
        );
    }

    #[test]
    fn context_digest_sign_final_without_init_fails() {
        let mut ctx = DsaSignatureContext::new(DsaVariant::Sha256, LibContext::get_default(), None);
        let err = ctx
            .digest_sign_final()
            .expect_err("digest_sign_final before init must fail");
        assert!(
            matches!(err, ProviderError::Init(_)),
            "expected Init, got {err:?}"
        );
    }

    #[test]
    fn context_digest_verify_final_without_init_fails() {
        let mut ctx = DsaSignatureContext::new(DsaVariant::Sha256, LibContext::get_default(), None);
        let err = ctx
            .digest_verify_final(b"any signature")
            .expect_err("digest_verify_final before init must fail");
        assert!(
            matches!(err, ProviderError::Init(_)),
            "expected Init, got {err:?}"
        );
    }

    // -------------------------------------------------------------------------
    // Descriptor surface
    // -------------------------------------------------------------------------

    #[test]
    fn descriptors_returns_ten_entries() {
        // Ten descriptors: one composable + nine fixed sigalg variants.
        // This corresponds to the `IMPL_DSA_SIGALG(...)` macro expansions
        // in `dsa_sig.c` lines 1000â€“1068.
        let descriptors = descriptors();
        assert_eq!(
            descriptors.len(),
            10,
            "expected ten DSA descriptor entries, got {}",
            descriptors.len()
        );
    }

    #[test]
    fn descriptors_first_entry_is_composable_dsa() {
        // The composable `"DSA"` entry must come first for stable
        // provider fingerprints and to match the C source ordering.
        let descriptors = descriptors();
        let first = descriptors.first().expect("at least one descriptor");
        assert!(
            first.names.iter().any(|n| *n == "DSA"),
            "first descriptor names={:?} must include \"DSA\"",
            first.names
        );
    }

    #[test]
    fn descriptors_cover_all_sigalg_variants() {
        // Every variant returned by `descriptors()` must be present exactly
        // once, covering the full set of names registered in the C source.
        let descriptors = descriptors();
        let primary_names: Vec<&'static str> = descriptors
            .iter()
            .map(|d| {
                *d.names
                    .first()
                    .expect("descriptor must have at least one alias")
            })
            .collect();
        let expected = [
            "DSA",
            "DSA-SHA1",
            "DSA-SHA2-224",
            "DSA-SHA2-256",
            "DSA-SHA2-384",
            "DSA-SHA2-512",
            "DSA-SHA3-224",
            "DSA-SHA3-256",
            "DSA-SHA3-384",
            "DSA-SHA3-512",
        ];
        assert_eq!(primary_names.len(), expected.len());
        for name in expected {
            assert!(
                primary_names.contains(&name),
                "expected descriptor primary name {name:?} missing from {primary_names:?}"
            );
        }
    }

    #[test]
    fn descriptors_carry_oid_aliases() {
        // The sigalg descriptors must export their canonical OIDs as
        // aliases. These OIDs are baked into `prov/names.h` in the C
        // source and are required for PKIX-conformant algorithm lookup.
        let descriptors = descriptors();
        let find_by = |needle: &str| -> &'static str {
            descriptors
                .iter()
                .find(|d| d.names.iter().any(|n| *n == needle))
                .and_then(|d| {
                    d.names
                        .iter()
                        .find(|n| n.starts_with(|c: char| c.is_ascii_digit()))
                        .copied()
                })
                .expect("descriptor with OID must exist")
        };
        // Spot-check a handful of OIDs known to be emitted by the C
        // source via the `PROV_NAMES_*` macros.
        assert_eq!(find_by("DSA"), "1.2.840.10040.4.1");
        assert_eq!(find_by("DSA-SHA1"), "1.2.840.10040.4.3");
        assert_eq!(find_by("DSA-SHA2-256"), "2.16.840.1.101.3.4.3.2");
        assert_eq!(find_by("DSA-SHA3-512"), "2.16.840.1.101.3.4.3.8");
    }

    #[test]
    fn descriptors_non_empty_property_and_description() {
        // Every descriptor must carry a non-empty property query and a
        // descriptive string so that provider introspection tools
        // (`openssl list`, `EVP_SIGNATURE_fetch` with property filters)
        // can present meaningful metadata.
        let descriptors = descriptors();
        for (i, d) in descriptors.iter().enumerate() {
            assert!(
                !d.property.is_empty(),
                "descriptor[{i}] property must be non-empty"
            );
            assert!(
                !d.description.is_empty(),
                "descriptor[{i}] description must be non-empty"
            );
            assert!(
                !d.names.is_empty(),
                "descriptor[{i}] names must be non-empty"
            );
        }
    }
}
